using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class TicketModelTrainer
{
    public static (ITransformer Model, string Metrics) TrainAndEvaluate(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Featurize text columns and combine with Priority into a single Features vector
        var pipeline = mlContext.Transforms.Text
                .FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject))
            .Append(mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on the held-out test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        var metricsReport =
            $"Macro Accuracy: {metrics.MacroAccuracy:F4}\n" +
            $"Micro Accuracy: {metrics.MicroAccuracy:F4}\n" +
            $"Log Loss:       {metrics.LogLoss:F4}\n" +
            $"Per-class log loss: {string.Join(", ", metrics.PerClassLogLoss.Select(l => l.ToString("F4")))}";

        mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);

        return (model, metricsReport);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController(
    PredictionEnginePool<TicketData, TicketPrediction> predictionPool) : ControllerBase
{
    [HttpPost("classify")]
    public ActionResult<TicketPrediction> Classify([FromBody] TicketRequest request)
    {
        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = predictionPool.Predict(input);

        return Ok(prediction);
    }
}

